#include <stdio.h>
#include <string.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    char s[100005];
    while (T--) {
        scanf("%s", s);
        int ok = 0;
        for (int i = 0; s[i]; ++i) {
            if (s[i] == '0' || s[i] == '5') { ok = 1; break; }
        }
        puts(ok ? "Yes" : "No");
    }
    return 0;
}

